parameters.query:
SELECT id, slug, name_de, name_tr
FROM cities
ORDER BY name_de ASC;

parameters.jsCode:
return {
  json: {
    raw_id: $json.raw_id,
    title: $json.title,
    city_id: $json.city_id,
    city_slug: $json.city_slug,
    starts_at: $json.starts_at,
    venue_name: $json.venue_name,
    category: $json.category,
    external_url: $json.external_url,
    quality_score: $json.quality_score,
    route: $json.route,
    review_reason: $json.review_reason
  }
};

const cityItems = $items('Load Cities').map(i => i.json);

function normalize(value) {
  return (value || '')
    .toString()
    .toLowerCase()
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/ç/g, 'c')
    .replace(/ğ/g, 'g')
    .replace(/ı/g, 'i')
    .replace(/İ/g, 'i')
    .replace(/ş/g, 's')
    .replace(/Ş/g, 's')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function slugify(value) {
  return (value || '')
    .toString()
    .toLowerCase()
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/ç/g, 'c')
    .replace(/ğ/g, 'g')
    .replace(/ı/g, 'i')
    .replace(/İ/g, 'i')
    .replace(/ş/g, 's')
    .replace(/Ş/g, 's')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 90);
}

function decodeEntities(s) {
  return String(s || '')
    .replace(/&#8211;/g, '–')
    .replace(/&#8212;/g, '—')
    .replace(/&#8220;/g, '"')
    .replace(/&#8221;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&nbsp;/g, ' ')
    .replace(/&#(\d+);/g, (_, n) => {
      const code = Number(n);
      return Number.isFinite(code) ? String.fromCharCode(code) : _;
    });
}

function cleanText(value) {
  return decodeEntities(String(value || ''))
    .replace(/\s+/g, ' ')
    .trim();
}

function yearIsValid(year) {
  const y = Number(year);
  return y >= 2024 && y <= 2031;
}

function cleanTitle(value) {
  let t = cleanText(value);

  t = t.replace(/^home\s*[-|:]\s*/i, '');
  t = t.replace(/^tickets?\s*[-|:]\s*/i, '');
  t = t.replace(/^events?\s*[-|:]\s*/i, '');
  t = t.replace(/^veranstaltungen\s*[-|:]\s*/i, '');
  t = t.replace(/^termine\s*[-|:]\s*/i, '');
  t = t.replace(/^discover\s*/i, '');
  t = t.replace(/^definition\s+of\s+/i, '');
  t = t.replace(/^concert tickets?\s*[-|:]\s*/i, '');

  t = t.replace(/\s*\|\s*adticket\.de$/i, '');
  t = t.replace(/\s*\|\s*eventim.*$/i, '');
  t = t.replace(/\s*\|\s*getgo.*$/i, '');
  t = t.replace(/\s*\|\s*ticketmaster.*$/i, '');
  t = t.replace(/\s*\|\s*reservix.*$/i, '');
  t = t.replace(/\s*[-–—]\s*(tgd|ditib|vikz|igmg)$/i, '');

  t = t.replace(/\s+/g, ' ').trim();

  return t || 'Untitled Event';
}

function isBadGenericTitle(title) {
  const t = (title || '').toLowerCase().trim();
  if (!t) return true;

  return (
    /^home\b/.test(t) ||
    /^discover\b/.test(t) ||
    /^definition\b/.test(t) ||
    /^tickets?\b/.test(t) ||
    /^concert tickets?\b/.test(t) ||
    /^events?\b$/.test(t) ||
    /^veranstaltungen\b$/.test(t) ||
    /^termine\b$/.test(t) ||
    /\badticket\b/.test(t) ||
    /\beventim\b/.test(t) ||
    /\bgetgo\b/.test(t) ||
    /\bticketmaster\b/.test(t) ||
    /\breservix\b/.test(t)
  );
}

const cityMatchers = cityItems.map(city => {
  const aliases = [city.slug, city.name_de, city.name_tr]
    .filter(Boolean)
    .map(normalize)
    .filter(v => v.length >= 3);

  return {
    ...city,
    aliases: [...new Set(aliases)].sort((a, b) => b.length - a.length)
  };
});

function findCityBySlug(slug) {
  return cityMatchers.find(c => c.slug === slug) || null;
}

function detectCity(text, cityGuess, sourceUrl) {
  const normalizedText = normalize(text);
  const normalizedUrl = normalize(sourceUrl || '');

  if (cityGuess) {
    const normalizedGuess = normalize(cityGuess);
    const direct = cityMatchers.find(c => c.aliases.includes(normalizedGuess));
    if (direct) return direct;
  }

  // zuerst direkte eindeutige Berlin/Köln-Signale
  if (/\bberlin\b/.test(normalizedText) || /\bberlin\b/.test(normalizedUrl)) {
    return findCityBySlug('berlin');
  }
  if (/\bkoeln\b|\bkoln\b|\bcologne\b/.test(normalizedText) || /\bkoeln\b|\bkoln\b|\bcologne\b/.test(normalizedUrl)) {
    return findCityBySlug('koeln');
  }

  for (const city of cityMatchers) {
    for (const alias of city.aliases) {
      if (normalizedText.includes(alias) || normalizedUrl.includes(alias)) return city;
    }
  }

  if (/\bnrw\b|\bnordrhein westfalen\b/.test(normalizedText)) return findCityBySlug('koeln');
  if (/\bbayern\b|\bbavaria\b/.test(normalizedText)) return findCityBySlug('muenchen');
  if (/\bhamburg\b/.test(normalizedText)) return findCityBySlug('hamburg');
  if (/\bhessen\b|\bfrankfurt\b/.test(normalizedText)) return findCityBySlug('frankfurt-am-main');
  if (/\bmuenchen\b|\bmunchen\b|\bmünchen\b/.test(normalizedText)) return findCityBySlug('muenchen');

  return null;
}

function parseDate(text) {
  const t = cleanText(text);

  // dd.mm.yyyy mit Uhrzeit
  const m1 = t.match(/\b(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{4})(?:[^\d]{0,20}(?:(?:um|ab|beginn|einlass|uhr)\s*)?(\d{1,2})[:.](\d{2}))?/i);
  if (m1 && yearIsValid(m1[3])) {
    const day = m1[1].padStart(2, '0');
    const month = m1[2].padStart(2, '0');
    const year = m1[3];
    const hour = (m1[4] || '19').padStart(2, '0');
    const minute = (m1[5] || '00').padStart(2, '0');
    return `${year}-${month}-${day}T${hour}:${minute}:00`;
  }

  // ISO
  const m2 = t.match(/\b(\d{4})-(\d{2})-(\d{2})(?:[T\s](\d{2}):(\d{2}))?/);
  if (m2 && yearIsValid(m2[1])) {
    const year = m2[1];
    const month = m2[2];
    const day = m2[3];
    const hour = (m2[4] || '19').padStart(2, '0');
    const minute = (m2[5] || '00').padStart(2, '0');
    return `${year}-${month}-${day}T${hour}:${minute}:00`;
  }

  const monthMap = {
    januar: '01', jan: '01',
    februar: '02', february: '02', feb: '02',
    maerz: '03', märz: '03', marz: '03', march: '03', mar: '03',
    april: '04', apr: '04',
    mai: '05', may: '05',
    juni: '06', june: '06', jun: '06',
    juli: '07', july: '07', jul: '07',
    august: '08', aug: '08',
    september: '09', sept: '09', sep: '09',
    oktober: '10', october: '10', okt: '10', oct: '10',
    november: '11', nov: '11',
    dezember: '12', december: '12', dez: '12', dec: '12'
  };

  // 12 April 2026
  const m3 = t.match(/\b(\d{1,2})\s+([A-Za-zÄÖÜäöüß]+)\s+(\d{4})(?:[^\d]{0,20}(?:(?:um|ab|beginn|einlass|uhr)\s*)?(\d{1,2})[:.](\d{2}))?/i);
  if (m3 && yearIsValid(m3[3])) {
    const day = m3[1].padStart(2, '0');
    const monthName = m3[2].toLowerCase();
    const year = m3[3];
    const month = monthMap[monthName];
    if (month) {
      const hour = (m3[4] || '19').padStart(2, '0');
      const minute = (m3[5] || '00').padStart(2, '0');
      return `${year}-${month}-${day}T${hour}:${minute}:00`;
    }
  }

  // April 12 2026
  const m4 = t.match(/\b([A-Za-zÄÖÜäöüß]+)\s+(\d{1,2})\s+(\d{4})(?:[^\d]{0,20}(?:(?:um|ab|beginn|einlass|uhr)\s*)?(\d{1,2})[:.](\d{2}))?/i);
  if (m4 && yearIsValid(m4[3])) {
    const monthName = m4[1].toLowerCase();
    const day = m4[2].padStart(2, '0');
    const year = m4[3];
    const month = monthMap[monthName];
    if (month) {
      const hour = (m4[4] || '19').padStart(2, '0');
      const minute = (m4[5] || '00').padStart(2, '0');
      return `${year}-${month}-${day}T${hour}:${minute}:00`;
    }
  }

  // 21.04 oder 21.04 um 19:30
  const m5 = t.match(/\b(\d{1,2})[.\/](\d{1,2})(?:[.\/](\d{4}))?(?:[^\d]{0,20}(?:(?:um|ab|beginn|einlass|uhr)\s*)?(\d{1,2})[:.](\d{2}))?/i);
  if (m5) {
    const day = m5[1].padStart(2, '0');
    const month = m5[2].padStart(2, '0');
    const year = m5[3] && yearIsValid(m5[3]) ? m5[3] : String(new Date().getFullYear());
    const hour = (m5[4] || '19').padStart(2, '0');
    const minute = (m5[5] || '00').padStart(2, '0');
    return `${year}-${month}-${day}T${hour}:${minute}:00`;
  }

  // Sonntag 21.04.
  const m6 = t.match(/\b(?:montag|dienstag|mittwoch|donnerstag|freitag|samstag|sonntag)[, ]+(\d{1,2})[.\/](\d{1,2})(?:[.\/](\d{4}))?(?:[^\d]{0,20}(?:(?:um|ab|beginn|einlass|uhr)\s*)?(\d{1,2})[:.](\d{2}))?/i);
  if (m6) {
    const day = m6[1].padStart(2, '0');
    const month = m6[2].padStart(2, '0');
    const year = m6[3] && yearIsValid(m6[3]) ? m6[3] : String(new Date().getFullYear());
    const hour = (m6[4] || '19').padStart(2, '0');
    const minute = (m6[5] || '00').padStart(2, '0');
    return `${year}-${month}-${day}T${hour}:${minute}:00`;
  }

  return null;
}

function parseJsonLdDate(rawPayloadJson) {
  if (!rawPayloadJson) return null;

  try {
    const payload = typeof rawPayloadJson === 'string'
      ? JSON.parse(rawPayloadJson)
      : rawPayloadJson;

    const candidates = [
      payload?.startDate,
      payload?.start_time,
      payload?.date,
      payload?.event?.startDate,
      payload?.jsonld?.startDate,
      payload?.fetch_meta?.startDate
    ].filter(Boolean);

    for (const c of candidates) {
      const txt = String(c).trim();
      const m = txt.match(/^(\d{4}-\d{2}-\d{2})(?:[T\s](\d{2}):(\d{2})(?::\d{2})?)?/);
      if (m && yearIsValid(m[1].slice(0, 4))) {
        const day = m[1];
        const hour = (m[2] || '19').padStart(2, '0');
        const minute = (m[3] || '00').padStart(2, '0');
        return `${day}T${hour}:${minute}:00`;
      }
    }
  } catch (e) {}

  return null;
}

function detectCategory(text, sourceUrl) {
  const t = `${text || ''} ${sourceUrl || ''}`.toLowerCase();

  if (/konzert|concert|live|muezik|müzik|sanat müziği|turk sanat|artist|band|singer|dj|performance/.test(t)) return 'concert';
  if (/festival|fest|kulturfest|street food|show/.test(t)) return 'festival';
  if (/theater|tiyatro|ausstellung|sergi|film|sinema|lesung|workshop|atolye|atelier|kultur|culture/.test(t)) return 'cultural';
  if (/iftar|ramadan|ramazan|cami|moschee|mosque|dua|religion|religious|mevlid/.test(t)) return 'religious';
  if (/familie|family|kinder|kids|child|cocuk|çocuk/.test(t)) return 'family';
  if (/business|networking|unternehmer|girişim|girisim|startup|firma/.test(t)) return 'business';
  if (/kurs|course|seminar|training|egitim|eğitim|panel|konferenz|conference/.test(t)) return 'education';
  if (/essen|food|kulinar|iftar dinner|brunch|baklava|kahvalti|kahvaltı/.test(t)) return 'food';
  if (/community|meetup|treffen|buluşma|bulusma|verein|dernek|etkinlik|veranstaltung|event/.test(t)) return 'community';

  return 'other';
}

function detectVenue(text) {
  const t = decodeEntities(String(text || ''));
  const parts = t.split(/\n|\r|\||;/).map(s => s.trim()).filter(Boolean);

  const venue = parts.find(line =>
    /halle|saal|zentrum|center|kultur|moschee|cami|hotel|arena|theater|cafe|restaurant|gemeinde|haus|salon|stage|club/i.test(line) &&
    line.length >= 3 &&
    line.length <= 90 &&
    !/facebook|instagram|youtube|twitter|datenschutz|impressum|skip to main content/i.test(line)
  );

  return venue || null;
}

function normalizeVenue(venue) {
  if (!venue) return null;

  const v = cleanText(venue)
    .replace(/^ort[:\s-]*/i, '')
    .replace(/^location[:\s-]*/i, '')
    .replace(/^venue[:\s-]*/i, '')
    .replace(/\s{2,}/g, ' ')
    .trim();

  if (!v) return null;
  if (v.length > 90) return null;
  if (/facebook|instagram|youtube|twitter|datenschutz|impressum/i.test(v)) return null;

  return v;
}

function detectOrganizer(text, sourceUrl) {
  const t = cleanText(`${text || ''} ${sourceUrl || ''}`);

  if (/\bditib\b/i.test(t)) return 'DITIB';
  if (/\bvikz\b/i.test(t)) return 'VIKZ';
  if (/\btgd\b/i.test(t)) return 'TGD';
  if (/\bigmg\b/i.test(t)) return 'IGMG';
  if (/yunus emre/i.test(t)) return 'Yunus Emre Enstitüsü';

  return null;
}

function looksLikeLandingPage(title, sourceUrl, rawText) {
  const t = `${title || ''}`.toLowerCase().trim();
  const u = `${sourceUrl || ''}`.toLowerCase();
  const body = `${rawText || ''}`.toLowerCase();

  const genericTitle =
    /^home\b/.test(t) ||
    /^discover\b/.test(t) ||
    /^definition\b/.test(t) ||
    /^tickets?\b/.test(t) ||
    /^events?\b$/.test(t) ||
    /^veranstaltungen\b$/.test(t) ||
    /^termine\b$/.test(t);

  const listingUrl = /\/calendar\b|\/kalender\b|\/events\b|\/veranstaltungen\b|\/termine\b/.test(u);
  const hasDateHint = /\d{1,2}[./-]\d{1,2}([./-]\d{4})?/.test(body) || /\d{4}-\d{2}-\d{2}/.test(body);

  return genericTitle || (listingUrl && !hasDateHint);
}

function isAggregator(sourceUrl) {
  return /adticket\.de|eventim|getgo\.de|ticketmaster|reservix|koelticket/i.test(sourceUrl || '');
}

const item = $json;
const itemId = String(item.id || '');
const text = cleanText(`${item.raw_title || ''}\n${item.raw_text || ''}`);
const title = cleanTitle((item.raw_title || '').trim() || 'Untitled Event');
const city = detectCity(text, item.city_guess, item.source_url);
const parsedDate = parseDate(text);
const payloadDate = parseJsonLdDate(item.raw_payload_json);
const startsAt = parsedDate || payloadDate || null;
const category = detectCategory(text, item.source_url) || 'other';
const venueName = normalizeVenue(detectVenue(item.raw_text || ''));
const organizerName = detectOrganizer(item.raw_text || '', item.source_url || '');
const externalUrl = item.source_url && item.source_url !== 'undefined' ? item.source_url : null;
const slugBase = slugify(title) || `event-${itemId.slice(0, 8) || 'unknown'}`;

let score = 0;
if (title && title.length >= 8 && title.length <= 140) score += 20;
if (city) score += 30;
if (startsAt) score += 30;
if (venueName) score += 8;
if (organizerName) score += 7;
if (externalUrl) score += 5;

let route = 'REVIEW';
let reviewReason = null;

const landing = looksLikeLandingPage(title, externalUrl, item.raw_text);
const aggregator = isAggregator(externalUrl || '');
const hasCity = !!city;
const hasDate = !!startsAt;
const badTitle = isBadGenericTitle(title);

if (badTitle) {
  route = 'REVIEW';
  reviewReason = 'BAD_TITLE';
} else if (aggregator) {
  route = 'REVIEW';
  reviewReason = 'TICKET_PLATFORM';
} else if (landing && !hasDate && score < 40) {
  route = 'REVIEW';
  reviewReason = 'LANDING_PAGE';
} else if (!hasCity) {
  route = 'REVIEW';
  reviewReason = 'CITY_NOT_MATCHED';
} else if (!hasDate) {
  if (score >= 35) {
    route = 'INSERT';
    reviewReason = null;
  } else {
    route = 'REVIEW';
    reviewReason = 'DATE_MISSING';
  }
} else {
  route = 'INSERT';
}

if (route === 'INSERT' && score < 25) {
  route = 'REVIEW';
  reviewReason = 'LOW_CONFIDENCE';
}

return {
  json: {
    raw_id: itemId,
    title,
    slug: `${slugBase}-${itemId.slice(-6) || 'raw'}`,
    description_de: item.raw_text || null,
    category,
    city_id: city ? city.id : null,
    city_slug: city ? city.slug : null,
    city_name_de: city ? city.name_de : null,
    starts_at: startsAt,
    venue_name: venueName,
    organizer_name: organizerName,
    external_url: externalUrl,
    quality_score: score,
    route,
    review_reason: reviewReason
  }
};

return {
  json: {
    raw_id: $json.raw_id,
    title: $json.title,
    description: $json.description_de || undefined,
    startsAt: $json.starts_at || undefined,
    venueName: $json.venue_name || undefined,
    citySlug: $json.city_slug || undefined,
    sourceCategory: ($json.category || 'other').toLowerCase(),
    sourceUrl: $json.external_url || undefined
  }
};

function parseDuplicate(message) {
  if (!message) return null;
  const match = String(message).match(/\{.*\}$/);
  if (!match) return null;
  try {
    return JSON.parse(match[0]);
  } catch {
    return null;
  }
}

const j = $json || {};

if (j.error) {
  const statusCode = j.error.status ?? null;
  const duplicateBody = statusCode === 409 ? parseDuplicate(j.error.message) : null;

  return {
    json: {
      raw_id: j.raw_id,
      resultType: statusCode === 409 ? 'duplicate' : 'error',
      eventId: duplicateBody?.eventId ?? null,
      submissionId: null,
      statusCode,
      ingestMessage: statusCode === 409 ? 'DUPLICATE_EVENT' : 'INGEST_ERROR'
    }
  };
}

return {
  json: {
    raw_id: j.raw_id,
    resultType: j.statusCode === 201 ? 'created' : 'error',
    eventId: j.body?.eventId ?? null,
    submissionId: j.body?.submissionId ?? null,
    statusCode: j.statusCode ?? null,
    ingestMessage: j.statusCode === 201 ? null : 'INGEST_ERROR'
  }
};
